// Merge expiring and high-usage into deduplicated list
const inputs = $input.all();
const seen = new Set();
const combined = [];

for (const item of inputs) {
    const order = item.json;
    if (!seen.has(order.order_id)) {
        seen.add(order.order_id);
        order.reminder_type = [];

        // Expiry warning
        if (order.expires_at) {
            order.reminder_type.push('expiry');
            const daysLeft = Math.ceil((new Date(order.expires_at) - new Date()) / (24*60*60*1000));
            order.message = `⚠️ Your ${order.plan_code || order.channel_origin} proxy expires in ${daysLeft} day${daysLeft === 1 ? '' : 's'}. Reply RENEW to keep access.`;
        }

        // Data usage warning
        if (order.data_total_gb && order.data_remaining_gb) {
            const used = parseFloat(order.data_total_gb) - parseFloat(order.data_remaining_gb);
            const pct = Math.round((used / parseFloat(order.data_total_gb)) * 100);
            order.data_pct = pct;
            if (!order.message) {
                order.message = `📊 You've used ${pct}% of your ${order.plan_code || order.channel_origin} data (${used.toFixed(1)}/${order.data_total_gb}GB). Reply UPGRADE for more.`;
            }
        }

        combined.push({ json: order });
    }
}
return combined;
